var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"사장실, 코핀 컴퍼니\\n<color=#ffd34c>관리자</color>, 화상 회의 중\\n보안국 청사 습격 ██분 전","JPN":"社長室、コフィンカンパニー\\n<color=#ffd34c>管理者</color>、ビデオ会議中\\n保安局官庁襲撃まであと██分","ENG":"Coffin Company, The CEO's office\\n<color=#ffd34c>Administrator</color>, Video Conference\\n██ minutes before the Department of National Security is attacked","TWN":"老闆辦公室，科芬公司\\n<color=#ffd34c>管理者</color>，視訊會議中\\n偷襲安全局大樓██分鐘前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모르스에, 마에스트로라…….","JPN":"モールスに、マエストロか……","ENG":"Mors, and Maestra...","TWN":"莫爾斯再加上指揮家……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"확실히 마에스트로는 골치 아픈 그림자라네. 매번 대처하기 곤란한 시기만 노려 움직였지.","JPN":"確かにマエストロは面倒なシャドウだ。いつも対処しにくい時期にだけ動いてたな。","ENG":"Indeed, Maestra is quite a troublesome Shadow. She only makes a move when it is difficult for me to take care of it.","TWN":"指揮家確實很令人頭疼呢，每次都專挑不好應付的時間行動。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하지만 핵을 파괴당했잖아. 모르스가 오인한 건 아니려나?","JPN":"でも核を破壊されたでしょう。モールスの勘違いじゃないかしら？","ENG":"But the core was destroyed. Maybe Mors was mistaken?","TWN":"不過她的核心不是已經遭到破壞嗎？還是莫爾斯誤會？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마에스트로와 같은 데모고르곤들은 이면세계에 일어나는 기상재해에 가깝다네.","JPN":"マエストロのようなデモゴルゴンは、裏世界で起きる気象災害に近い。","ENG":"Demogorgons like Maestra are like massive weather disasters to Counterside.","TWN":"像指揮家這類的魔神，就類似在異界發生的氣象災害。"},"stage":{"bg":"HARMONY_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대기의 흐름에 따라 태풍이 일어나는 것처럼, 조건이 갖춰지면 발생하게 되지.","JPN":"大気の流れによって台風が生じるように、条件が揃えば発生する。","ENG":"Just like how typhoons occur when strong winds hit certain areas of the ocean, Demogorgons occur when certain conditions are met.","TWN":"就像颱風會順著氣流形成一樣，只要條件滿足就會發生。"},"stage":{"bg":"HARMONY_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"파괴된 핵이 다시 생성되려면 아득한 시간이 걸리네만, 이번 케이스는 조금 다른 것 같군.","JPN":"破壊された核が再生成されるにはものすごく時間がかかるんだが、今度のケースは少し違うようだな。","ENG":"It normally takes a long time for the destroyed core to be re-formed, but this case seems a little different.","TWN":"通常遭破壞的核心若要復生，會需要花很長的時間，但這次似乎是個特例。"},"stage":{"bg":"HARMONY_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……트러블 슈팅 작전이 공식적으로 종결된 직후였지.","JPN":"……トラブルシューティング作戦が公式的に終結となった直後だった。","ENG":"...It was at the end of Operation Troubleshooting.","TWN":"……故障排除作戰正式結束之後，"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"현실세계에 있던 전대들이 전부 동원되어 <color=#ffd34c>이 나라</color>를 이잡듯 뒤졌어.","JPN":"現実世界にいた戦隊が全部動員されて、<color=#ffd34c>この国</color>を隅々まで探し回ったわ。","ENG":"All Divisions in Normalside were mobilized to comb through <color=#ffd34c>this very country</color> for her.","TWN":"便動員所有在現實世界的戰隊，地毯式搜查<color=#ffd34c>這個國家</color>，"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"마에스트로의 예상 도착 좌표는 바로 여기, 타나베린이었으니까.","JPN":"マエストロの予想到着座標はここ、タナベリンだったから。","ENG":"Because Maestra’s predicted arrival coordinates were right here in Tanaberin.","TWN":"結果發現指揮家的預計抵達座標就是這裡 達那貝林。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하지만 소득은 없었으려나. 예상 도착 좌표에서 찾은 생존자들을 제외하면.","JPN":"でも無駄骨だったのかな。予想到着座標で見つかった生存者を除けばね。","ENG":"But to no avail. There wasn’t anyone at the predicted arrival coordinates except for those survivors.","TWN":"但是卻一無所獲，在預計抵達座標的位置只有找到倖存者。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대외적으로는 건국기념전당 폭발 사고로 알려졌지.","JPN":"対外的には建国記念館の爆発事故で知られているな。","ENG":"To the public, it was known as the National Foundation Hall Explosion.","TWN":"對外的說法是建國紀念堂爆炸事件。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 마에스트로가 현실세계로 부상하면서 일으킨 여파였는데 말이야.","JPN":"そう。実はマエストロが現実世界に浮上した余波だったんだけどね。","ENG":"Right. It was an aftereffect of Maestra’s emergence into Normalside.","TWN":"沒錯，指揮家躍入現實世界後產生的風波。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"당시 정부는……. 반정부 단체의 소행이라고 주장했었나?","JPN":"当時の政府は……反政府団体の仕業だと主張したっけ？","ENG":"The government... Did they claim it as an act of the anti-government organization?","TWN":"當時……政府說是反政府團體的行為嗎？"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇지. 그 시절에도 이 나라의 정세는 무척 혼란스러웠다네.","JPN":"ああ。その頃もこの国の情勢は極めて混乱していた。","ENG":"Correct. Even back then, the situation in this country was that of complete chaos.","TWN":"沒錯，那時候這個國家的局勢非常混亂，"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"원인불명의 사고……. 생존자도 둘뿐이니 선전에 쓰기엔 안성맞춤이었을 걸세.","JPN":"原因不明の事故……生存者も二人だけだったから宣伝には打ってつけだっただろう。","ENG":"An incident of unknown causes... with only two survivors it was perfect for their propaganda machine.","TWN":"原因不明的事件……倖存者也只有2位，很適合拿來作為政治操弄。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"모르스는 그 레버넌트란 여자를 마에스트로로 여기는 모양이야.","JPN":"モールスはあのレヴナントという女をマエストロと考えてるようなの。","ENG":"Mors seems to believe that Revenant is Maestra.","TWN":"莫爾斯好像認為那個叫亡靈的女生就是指揮家。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"당신은 어떻게 생각해?","JPN":"あなたはどう思う？","ENG":"What do you think?","TWN":"你認為呢？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"당시 조사 결과로는 확인 불가라 모녀에게 감시만 붙인 걸로 기억하거든.","JPN":"あの時の調査結果では確認不可だったから、親子に監視をつけるだけだったのを覚えてる。","ENG":"At the time, even after investigating it was impossible to know for sure. I remember ordering that the mother and daughter be watched.","TWN":"當時的調查結果，我記得是無法確認，因此就決定暫時先監視母女二人。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"상황을 보아하니 그나마도 관리 실패로 흐지부지됐던 것 같고.","JPN":"状況から察すると、それも管理失敗でうやむやになったらしいし。","ENG":"It appears that fizzled out due to the Administration Failure.","TWN":"看這情況，可能因為管理失敗的關係就沒有下文。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그랬지. 본격적인 연구를 지시했지만 당시는 지금처럼 클리포트 게임을 앞둔 상황이었다네.","JPN":"そうだったな。本格的な研究を指示したが、当時は今のようにクリフォトゲームを目の前にした状態だった。","ENG":"Indeed. I had ordered a full-scale study into the matter at the time, but, similar to now, it was right before the Qliphoth Game.","TWN":"沒錯，雖然有說要正式進行研究，但當時和現在一樣，正好都是面臨到逆卡巴拉遊戲的情況。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 때의 나는 엘리시움 필하모닉이 우리 등 뒤에 비수만 꽂을 수 없다면 충분하다고 생각했겠지.","JPN":"あの時の私は、我々の背にエリシウムフィルハーモニーが刃を突き付けることがないなら、それで十分だと思ったんだろう。","ENG":"At the time, I believed it to be enough if the Elysium Philharmonic couldn’t stab us in the back.","TWN":"那時候的我，以為只要愛樂組織對我們不構成威脅就好。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……일전에 그로니아를 방문했던 적이 있다네.","JPN":"……以前、グロニアを訪ねたことがある。","ENG":"...I visited Gronia the other day.","TWN":"……我之前有去一趟格羅尼亞。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"루이제 슈나이더 여사를 만날 수 있었지만 확신을 갖기는 어려웠지.","JPN":"ルイーゼ・シュナイダー女史に会えたが、確信は持てなかった。","ENG":"I was able to meet Louise Schneider, but I still couldn’t be sure.","TWN":"雖然有見到露易絲·修奈德女士，但還是無法確定。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래? 당신이 판단을 보류하다니 별일이네.","JPN":"そう？　あなたが判断を保留にするなんて珍しいわね。","ENG":"Really? It’s not often you need to put off making a judgement.","TWN":"這麼稀奇？竟然有你無法判斷的時候？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럴 수밖에. 본인이 말하길 꺼리는 눈치기도 했거니와…….","JPN":"仕方ない。本人が話したくない様子だったこともあるが……","ENG":"I had no choice. She was rather unwilling to talk and well...","TWN":"沒辦法，因為她本人不太願意談……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"당시엔 순혈지식 연대에게 쫓기던 처지라 시간이 촉박했거든.","JPN":"当時、純血知識連帯に追われていたので時間がなかったんだ。","ENG":"At the time I was being chased by the Pureblood Knowledge Regiment, so I was a little short on time.","TWN":"而且當時正在追捕純血知識年代，時間有點急迫。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"순혈지식 연대?","JPN":"純血知識連帯？","ENG":"Pureblood Knowledge Regiment?","TWN":"純血知識年代？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"반군 세력 중에 초월지식 학회와 맞닿아 있던 곳이지.","JPN":"反乱軍勢力の中で超越知識学会と関わりがあったところだ。","ENG":"It’s a faction within the rebel forces that associated with the Society for Preternatural Research.","TWN":"他們叛軍勢力中有和超越學會合作的組織。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사이버 캣이 활약해 준 덕분에 수뇌부를 소탕하지 않았다면 지금보다 사정이 복잡해졌을 거야.","JPN":"サイバーキャットの活躍によって首脳部が掃討されなかったら、状況は今よりもっと複雑になっただろう。","ENG":"The situation would have been far more complicated if it weren’t for Cyber Cat’s heroics in taking out their leadership.","TWN":"幸虧賽博貓出手，萬一沒有除掉首腦的話，情況可能會比現在更複雜。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……제프티도 그렇고, 그것들은 안 끼어드는 데가 없네.","JPN":"……ジェフティもそうだし、そいつらは頭を突っ込みすぎね。","ENG":"...Jehuty too, those guys are everywhere.","TWN":"……傑夫堤也是，什麼壞事都跟他們有關！"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"학회의 가장 위험한 무기는 암암리에 사회에 뿌리내린 세력 그 자체라네.","JPN":"学会の一番危険な武器は、社会に密かに根付いている勢力そのものだ。","ENG":"The Society’s most dangerous weapon, is the power itself that secretly takes root in society.","TWN":"學會最危險的武器，就是默默滲透社會的勢力本身。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지식의 격차는 힘을 창출한다고 하지 않나?","JPN":"知識の差は力を生み出すというだろう。","ENG":"Is it not said that the knowledge gap leads to power?","TWN":"不是說知識就是力量嗎？"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음……. 좋아. 요약하자면 이런 뜻이려나.","JPN":"ふうん……わかった。要するにこういう意味かな。","ENG":"Hmm...Okay. So to sum things up...","TWN":"嗯嗯……總結來說是這個意思嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"심각하게 꼬인 건이지만, 클리포트 게임으로 발등에 불 떨어졌으니 현장 재량으로 알아서 처리해 주길 바란다?","JPN":"深刻にもつれた件だけど、クリフォトゲームで尻に火がついたから現場の裁量で処理して欲しいと？","ENG":"The situation’s twisted, but since we’re running out of time because of the Qliphoth Game, we should take care of it with our own discretion?","TWN":"雖然事情很複雜，但現在觸發逆卡巴拉遊戲之火已經燃起，你是希望我自動一點把事情處理好嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 걱정 말게. 이래봬도 관리자인데 그런 무책임한 심보로 일처리를 하겠나.","JPN":"はは、心配無用だ。こう見えても管理者なのに、そんな無責任な態度で対応するわけないだろう。","ENG":"Ha ha. Don’t worry. I may not look like it, but I am the Administrator. How could I handle things with such an irresponsible attitude?","TWN":"哈哈，別擔心，再怎麼說我也是管理者，怎麼會做事情這麼不負責任呢？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래? 류드밀라의 순정에 깃발을 푹 꽂아 놓고 나 몰라라 하는 분께서?","JPN":"あら、そう？　リュドミラの純情をもてあそんでおきながら、知らんぷりをしてる人が？","ENG":"Says the person who turns a blind eye to Lyudmila’s guileless affection?","TWN":"是嗎？你明明就利用盧德米拉的純情，還裝傻？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……크흠, 흠. 상사로서 성실한 부하 직원을 챙겨 주는 걸 곡해하지 말게.","JPN":"……コホン、コホン。上司として真面目な部下を気にかけてあげただけだ、曲解しないでほしいな。","ENG":"Ahem…Well. Don’t get me wrong when it comes to taking care of my dear, dear subordinates.","TWN":"……咳咳，我身為上司，關心忠心的下屬是應該的，別曲解我的意思。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그렇겠지. 우리 부사장님도 당신 밑에서 일하느라 고생이 많겠어.","JPN":"そうでしょうね。うちの副社長もあなたの下で苦労するわ。","ENG":"I guess. Vice President must have a really difficult time working for you.","TWN":"也是～我看我們副總在你底下做事一定很辛苦～"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"말에 뼈가 있군. 그것도 생선 가시처럼 빽빽하게.","JPN":"言葉にトゲがあるな。それもハリネズミのようにぎっちりと。","ENG":"There are hidden meanings in your words. Like bones in a fish, all densely packed together.","TWN":"你說話帶刺喔，而且還是跟魚骨頭一樣刺。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗. 나름 정중하게 말했는데 너무 노골적이었으려나.","JPN":"ふふっ。私なりに丁重に言ったはずだったけど、あからさま過ぎた？","ENG":"Fuu fuu... I was trying to be polite, but I was a little too direct?","TWN":"呵呵，我講得一派正經，結果還是被你聽出來啦？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"알겠어. 지금은 우선 레버넌트의 신병을 확보하는 게 우선이겠네.","JPN":"わかったわ。今はとりあえずレヴナントの身柄を確保すべきね。","ENG":"Understood. The first order of business is to secure Revenant.","TWN":"好吧，現在首要之務就是確認亡靈的身分。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마에스트로가 인간으로 의태한 상태라면, 가장 좋은 방안은 현상 유지일 걸세.","JPN":"マエストロが人間に擬態した状態なら、一番いい方法は現状を維持することだろう。","ENG":"If Maestra really is mimicking a human being, the best thing to do is maintain the status quo.","TWN":"若指揮家已經擬態成人類，那最好的方法就是維持現狀。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그간 기회가 있었는데도 20년 넘도록 얌전했다는 건…….","JPN":"今までチャンスがあったのにもかかわらず、20年以上大人しかったというのは……","ENG":"Meanwhile, despite having opportunities, she’s been quiet for over 20 years...","TWN":"之前明明有機會，她卻還是不動聲色20年……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뒤집어 생각하면, 주체적으로 본모습을 되찾을 수 없다는 뜻이겠지.","JPN":"逆に考えれば、自分だけでは本来の姿を取り戻せないという意味だ。","ENG":"If you really think things through, it means she can’t independently transform back into her true form.","TWN":"反過來想，也就是她無法自行恢復原本的樣貌吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 대신 돌아가면 우리 애들 뺑이치게 만든 대가는 확실하게 받아낼 거야.","JPN":"そう。その代わり、帰ったらうちの子どもたちをこき使った対価はしっかり貰うからね。","ENG":"Fine. But in return, when it is completed, my kids better get compensated fairly.","TWN":"嗯嗯，你讓那些孩子們吃那麼多苦，等我回去後一定會向你討這筆費用的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"사람이 제일 많은 도시인데도 침식지대처럼 침식파가 흐르더라?","JPN":"人が一番多い街のくせに、侵食地帯みたいに侵食波が流れてたし？","ENG":"The city may have a lot of people, but there are still so many Corruption rays just like a Corrupted Area.","TWN":"在人潮最多的地方，竟然跟侵蝕地帶一樣有侵蝕波？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……미안하군. 내가 줄 수 있는 거라곤 휴가밖에 없어서.","JPN":"……悪いな。私からあげられるのは休暇くらいだ。","ENG":"...Sorry. I’m afraid all I can offer is extra vacation.","TWN":"……抱歉，我能給的就只有休假。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"관리자님, 죄송하지만 한 가지 여쭤 봐도 되겠습니까?","JPN":"管理者様、申し訳ありませんが一つよろしいですか？","ENG":"Sir, my apologies, but could I ask you a question?","TWN":"管理者大人，不好意思，我可以問一件事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"예고르? 웬일이야?","JPN":"イェゴール？　どうしたの？","ENG":"Yegor? What’s up?","TWN":"伊高爾？你怎麼啦？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"편히 말해 보게, 무슨 일인가?","JPN":"気にせず話してみなさい、なんだね？","ENG":"No need to be so stiff. What’s the matter?","TWN":"你儘管問，有什麼事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"이건, 순전히 제 착각이라고 생각합니다만…….","JPN":"これは、ただの私の思い違いだとは思いますが……","ENG":"I think I may be delusional for thinking this but...","TWN":"這只是我個人的猜測……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"앨리스 전대장님께 혹시 여동생이나 따님이 있었습니까?","JPN":"アリス戦隊長に、もしや妹さんや娘さんがいらっしゃいましたか？","ENG":"Did Commander Alice have a sister or daughter by chance?","TWN":"請問艾莉絲戰隊長有妹妹或女兒嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앨리스 전대장……. 시무르그를 요격했던 앨리스 전대장 말인가?","JPN":"アリス戦隊長……シムルグを迎撃したアリス戦隊長のことか？","ENG":"Commander Alice... You mean Commander Alice who intercepted Simurgh?","TWN":"艾莉絲戰隊長……你是說迎擊過西摩格的艾莉絲戰隊長嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"글쎄……. 적어도 남아 있는 인적 사항에는 없군.","JPN":"どうだろうな……少なくとも残っているデータには載っていないな。","ENG":"Well... There’s no mention of it in her personal data records.","TWN":"這個嘛……我只知道她沒有留下個人資料。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뭔가 마음에 걸리는 일이라도 있나?","JPN":"何か引っかかることでもあるのか？","ENG":"Is there something bothering you?","TWN":"有什麼讓你覺得掛心的事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"아. 아닙니다. 확인해 주셔서 감사합니다.","JPN":"あ。いいえ。ご確認ありがとうございます。","ENG":"Ah. No sir. Thank you for checking for me.","TWN":"不，沒有，謝謝您的回答。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"예고르, 슈나이더 모녀 옆에 붙어 있던 애 때문에 그러니?","JPN":"イェゴール、シュナイダーの親子のそばにいた子が気になるの？","ENG":"Yegor, are you talking about the kid next to Louise Schneider and her daughter?","TWN":"伊高爾，你是因為在修奈德母女身旁的那個女生，才這樣問的嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님도 보시지 않았습니까?","JPN":"副戦隊長もご覧になったでしょう？","ENG":"Don’t you see the resemblance too, Deputy Commander?","TWN":"副戰隊長你也有看見吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"머리색만 다를 뿐이지, 생김새는 분명 제가 알던 그 분이셨습니다.","JPN":"髪の色が違うだけで、外見は確かに私の知っていたあの方でした。","ENG":"The hair color is different, but the appearance is definitely that of someone I know.","TWN":"除了髮色不同，她的長相和我認識的艾莉絲一模一樣。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"닮았다는 건 나도 이해해.","JPN":"似てるってことは私もわかる。","ENG":"I agree that they look very similar.","TWN":"我知道她們長得很像。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하지만 앨리스 전대장은 시무르그를 요격하고 허수 공간으로 사라졌어.","JPN":"でもアリス戦隊長はシムルグを迎撃した後、虚数空間へと消えた。","ENG":"But Commander Alice intercepted Simurgh and disappeared into imaginary space.","TWN":"但艾莉絲戰隊長在迎擊西摩格後，便消失在量子空間裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아무리 그 사람이라도 맨몸으로 허수 공간에서 벗어날 가능성은 0이야.","JPN":"いくらあの人でも武装もせずに虚数空間から出られる可能性は0に近い。","ENG":"No matter how capable she is, the probability of escaping barehanded from imaginary space is zero.","TWN":"即使是她，在沒有任何外力的協助下，要離開量子空間的機率是0。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"……예. 저도 기우라고 생각합니다, 부전대장님.","JPN":"……はい。私も杞憂かと思います、副戦隊長。","ENG":"...Agreed. I also feel this concern is ungrounded, Deputy Commander.","TWN":"……是， 副戰隊長，我也認為只是湊巧長得像。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"지금은 마에스트로로 추정되는 여성이 더 급선무겠죠. 괜한 말을 꺼내서 죄송합니다.","JPN":"今はマエストロと思われる女性が先ですね。余計な話を持ち出して、申し訳ありません。","ENG":"The woman believed to be Maestra is presently more important. I apologize for bringing it up.","TWN":"現在當務之急，是查明那個女生到底是不是指揮家對吧？抱歉，我不該提起這些的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아냐. 이해해. 살아 있었으면 든든했을 테니까.","JPN":"いいえ。いいのよ。生きていたらきっと頼りになったはずだからね。","ENG":"Please, I understand. It would be relieving to know that she is still alive.","TWN":"沒事，我明白，我也希望她還活著。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"모네카? 레버넌트는 아직 보안국 청사에 있으려나?","JPN":"モネカ？　レヴナントはまだ保安局庁舎にいる？","ENG":"Moneka? Is Revenant still in the Department of National Security?","TWN":"莫奈卡？亡靈還在安全局裡嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"네. 연행 이후 별다른 움직임은 감지되지 않았습니다.","JPN":"はい。連行されて以来、これといった行動は感知されてません。","ENG":"Yes. I have not picked up any further movement after the arrest.","TWN":"是的，她遭逮捕後，還沒有移動的跡象。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"어디 멀리 데려가지 않아서 다행이네.","JPN":"どこか遠いところに連れて行かれなくてよかったわ。","ENG":"I’m glad they didn’t take her too far.","TWN":"幸好還沒走遠。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"얘들아, 대인용 비살상 장비 챙겨. 모네카는 내부 구조 분석해 주고.","JPN":"みんな、対人用の不殺傷装備を準備しなさい。モネカは内部の構造を分析して。","ENG":"Kids, prepare your non-lethal gear. Moneka, analyze the interior layout of the building.","TWN":"孩子們，準備好非致命性的裝備，莫奈卡你分析一下內部結構。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"들키지 않아야 하는 비공식 작전이라니, 옛날 생각 나는군요.","JPN":"隠密の非公式作戦なんて、昔を思い出しますね。","ENG":"Stealth operations where we have to avoid detection, it reminds me of the old days.","TWN":"像這樣不能被發現的非公開作戰，讓我想起以前的事呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 일단은 비밀결사였으니까.","JPN":"まあ、一応は秘密結社だったしね。","ENG":"Well, we were initially a secret organization.","TWN":"嗯，畢竟現在是秘密組織。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>정부 일이니 관리국은 개입하지 마라</color>면서 연행해 갔지?","JPN":"<color=#ffd34c>政府の仕事だから管理局は介入するな</color>、なんて言いながら連行して行ったでしょ？","ENG":"They said <color=#ffd34c>it’s government business, so the Administration shouldn’t intervene</color> and took Revenant in, right?","TWN":"<color=#ffd34c>對方是說這是政府的事，管理局別插手</color>，然後把人帶走的吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"증거도 없고 목격자도 없이 수감 중인 용의자가 사라지면 뭐라고 할지 기대되네.","JPN":"証拠も、目撃者もなく収容中の容疑者が消えたら何って言うか楽しみだわ。","ENG":"I can’t wait to hear what they say once their suspect disappears with no evidence or witnesses.","TWN":"真是期待，若是收監中的嫌犯，在人證、物證都沒有的情況下消失不見，政府會說什麼呢？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"잠시만요, 부전대장님! 보안국 청사 근방에 모르스로 추정되는 개체가 포착되었어요!","JPN":"待ってください、副戦隊長！　保安局庁舎の辺りにモールスと思しき個体が感知されました！","ENG":"Wait a minute, Deputy Commander! An object believed to be Mors has been detected near the National Security's main office!","TWN":"先等一下，副戰隊長！在安全局附近發現疑似莫爾斯的個體！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"모르스? 레버넌트 때문인가?","JPN":"モールス？　レヴナントが目的か？","ENG":"Mors? Could it be because of Revenant?","TWN":"莫爾斯？她是來找亡靈的嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"지난번에 조용히 물러난 것 아니었습니까? 그런데 어째서……?","JPN":"この前はおとなしく引き下がったのではないですか？　なのにどうして……？","ENG":"Didn’t she just walk away last time? But why...?","TWN":"她上次不是已經默默消失嗎？怎麼會……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"글쎄, 단독으로 나타난 걸로 봐선…….","JPN":"さあ、一人で現れたところを見ると……","ENG":"Well, given that she has appeared alone...","TWN":"我也不清楚，不過她會獨自現身……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭔가 문제가 생긴 거겠지?","JPN":"何か問題が起きたようね？","ENG":"Something must have happened, right?","TWN":"就表示有發生什麼問題吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"작전을 서두르자. 레버넌트와 마주치면 무탈하란 보장이 없어.","JPN":"作戦を急ぎましょう。レヴナントが出くわしたら、無事でいられるかどうかわからないもの。","ENG":"Let us hurry with the operation. If Revenant runs into her, there’s no guarantee she’ll be safe.","TWN":"動作要快！萬一被她先找到亡靈，難保會沒事！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"}]`);export{e as default};